async function seedUniversities() {
  // 先清空旧数据再导入，避免脏数据残留
  const existingCount = await University.countDocuments();
  if (existingCount === universities.length) {
    console.log(`大学数据已存在 (${existingCount} 条)，跳过初始化`);
    return;
  }

  if (existingCount > 0 && existingCount < universities.length) {
    console.log(`检测到不完整数据 (${existingCount}/${universities.length})，清空重新导入...`);
    await University.deleteMany({});
  }

  try {
    const result = await University.insertMany(universities, { ordered: false });
    console.log(`已初始化 ${result.length} 所大学数据`);
  } catch (error) {
    if (error.writeErrors) {
      const inserted = error.insertedDocs?.length || 0;
      console.log(`大学数据部分导入: 成功 ${inserted} 条, 跳过 ${error.writeErrors.length} 条`);
      if (inserted < universities.length) {
        const remaining = universities.length - inserted;
        // 补充插入失败的数据
        const failedIndices = error.writeErrors.map(e => e.index);
        const remainingData = universities.filter((_, i) => failedIndices.includes(i));
        if (remainingData.length > 0) {
          try {
            await University.insertMany(remainingData, { ordered: false });
            console.log(`补充导入完成`);
          } catch (retryErr) {
            console.log(`补充导入后共有 ${await University.countDocuments()} 所大学`);
          }
        }
      }
    } else {
      console.error('初始化大学数据失败:', error.message);
    }
  }
}

module.exports = seedUniversities;
